    await client.query("DELETE FROM diagnostic_results WHERE assignment_id=$1", [DEMO_ASSIGNMENT_ID]);
    await client.query("DELETE FROM attempts WHERE assignment_id=$1", [DEMO_ASSIGNMENT_ID]);
  });
